      type: 'object',
      properties: {
        success: { type: 'boolean', example: true },
        message: { type: 'string', example: 'Profile retrieved successfully' },
        data: { type: 'object' },
      },
    },
  })
  async getProfile(@CurrentUser() user: AuthUser) {
    return {
      success: true,
      message: 'Profile retrieved successfully',
      data: user,
    };
  }
}

