  @ApiPropertyOptional({ description: 'Coefficient de prorata (0–1 ou 1 = 100 %)', example: 1 })
  @IsOptional()
  @Type(() => Number)
  @IsNumber({ maxDecimalPlaces: 2 })
  @Min(0)
  prorata?: number;
}

