    const existing = await this.prisma.permission.findFirst({
      where: { name: dto.name },
    });
    if (existing) throw new ConflictException(`Permission "${dto.name}" already exists`);

    return this.prisma.permission.create({
      data: {
        typeId: dto.typeId,
        name: dto.name,
        code: dto.code,
        isActive: dto.isActive ?? true,
      },
    });
  }

